const ComplexCard = ({ title, children }) => {
  return (
    <Box
      sx={{
        padding: 3,
        borderRadius: 2,
        boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
        backgroundColor: '#fff',
        borderLeft: `5px solid ${'#1976d2'}`
